  static int indexForDate(DateTime date) {
    if (_facts.isEmpty) {
      return 0;
    }

    final onlyDate = DateTime(date.year, date.month, date.day);
    final startDate = DateTime(2024, 1, 1);
    final dayNumber = onlyDate.difference(startDate).inDays + 1;
    return (dayNumber.abs() - 1) % _facts.length;
  }

  static String getInfoForDate(DateTime date) {
    if (_facts.isEmpty) {
      return 'لا توجد معلومة متاحة اليوم.';
    }

    final index = indexForDate(date);
    return _facts[index];
  }

  static List<String> get allFacts => List<String>.from(_facts);
}

class DailyHealthTips {
  static int dayOfYear(DateTime date) {
    final start = DateTime(date.year, 1, 1);
    return date.difference(start).inDays + 1;
  }

  static int tipIndexForDate(DateTime date) {
    return DailyHealthInfo.indexForDate(date);
  }

  static String getTipForDate(DateTime date) {
    return DailyHealthInfo.getInfoForDate(date);
  }
}
